package chi

import "net/http"

// setPathValues sets the path values for the request, as detailed
// in the net/http package for the (*http.Request) PathValue method,
// added in Go 1.22.
func setPathValues(r *http.Request, routeCtx *Context) {
	for i, key := range routeCtx.URLParams.Keys {
		if key == "*" || key == "" {
			continue
		}
		value := routeCtx.URLParams.Values[i]
		r.SetPathValue(key, value)
	}
}
"}

